<script setup lang="ts">import { computed } from 'vue';import type { Agent,Room,RoomRuntime } from '../domain/types';import NpcAvatar from './NpcAvatar.vue';const p=defineProps<{room:Room;runtime:RoomRuntime;agents:readonly Agent[];central?:boolean}>();const current=computed(()=>p.agents.find(a=>a.id===p.runtime.currentAgentId)||p.agents[0]);const statusText=computed(()=>({waiting:'候命',discussing:'讨论中',synthesizing:'整理结论',completed:'完成',failed:'需处理',skipped:'无需参与'}[p.runtime.status]));</script>
<template><RouterLink class="room-building" :class="[runtime.status,{central}]" :to="{name:'room',params:{teamId:room.teamId,roomId:room.id}}" :aria-label="`${room.name}，${statusText}`"><div class="room-sign"><span v-if="runtime.status==='completed'" aria-hidden="true">✓</span><span v-if="runtime.status==='failed'" aria-hidden="true">!</span>{{statusText}}</div><div class="roof"><i></i></div><div class="wall front"><div class="door"></div><div class="window left"><b></b></div><div class="window right"><b></b></div><span class="lantern l1">灯</span><span class="lantern l2">灯</span></div><div class="wall side"></div><div class="room-title">{{room.name}}</div><div class="room-npcs"><NpcAvatar v-if="current" :agent="current" :status="runtime.currentNpcStatus" compact active/><span v-if="agents.length>1">同席 {{agents.length-1}} 位</span></div><div class="room-activity">{{runtime.activityLabel}}</div></RouterLink></template>
